html.script:
function sp(t) {
  document.getElementById('gen-prompt').value = t;
  document.getElementById('gen-prompt').focus();
}
function clearInput() { document.getElementById('gen-prompt').value = ''; }
function generateCode() {
  var prompt = document.getElementById('gen-prompt').value;
  var formatRole = document.getElementById('gen-format').value;
  if (!prompt.trim()) { alert('Harap deskripsikan desain dashboard Anda.'); return; }

  var q = '| makeresults \n| eval _raw="" \n| geminianalyze prompt=' + JSON.stringify(prompt) + ' role=' + JSON.stringify(formatRole) + ' model="gemini-3.1-pro" \n| table gemini_analysis';

  window.location.href = window.location.origin + '/en-US/app/gemini_soc_assistant/search?q=' + encodeURIComponent(q) + '&earliest=-1m&latest=now';
}
